import React, { useState } from 'react'

const Taskcard = ({ task, handleDeleteTask }) => {
  const [subtasks, setSubtasks] = useState([])

  function addtask() {
    setSubtasks(prev => [...prev, { activity: '', id: Date.now(), completed: false }])
  }

  function handleSubtaskChange(id, value) {
    setSubtasks(prev =>
      prev.map(sub => (sub.id === id ? { ...sub, activity: value } : sub))
    )
  }

  function handleCheckbox(id, subcompleted) {
    setSubtasks(prev =>
      prev.map(p => (p.id === id ? { ...p, completed: !subcompleted } : p))
    )
  }

  function handleBlur(id, value) {
    if (value.trim() === '') {
      setSubtasks(prev => prev.filter(sub => sub.id !== id))
    }
  }

  return (
    <>
      <div className='task-card'>
        <div className='taskcard-header'>
          <div className='task-title'>
            {task.title}
          </div>
          <div className='task-icons'>
            <div className='sub-icon'>
              <button className='icon-button' onClick={addtask}>
                <img className='icon-img' src='/assets/add.png' alt="Add" />
              </button>
            </div>
            <div className='sub-icon'>
              <button onClick={() => handleDeleteTask(task.id)} className='icon-button'>
                <img className='icon-img' src='./assets/delete.png' alt="Delete" />
              </button>
            </div>
          </div>
        </div>

        <div className='sub-tasks'>
          {subtasks.map((sub) => (
            <div className='sub-task-items' key={sub.id}>
              <div>
                <input
                  type='checkbox'
                  onClick={() => handleCheckbox(sub.id, sub.completed)}
                  className='subtask-checkbox'
                />
                <input
                  className={`${sub.completed ? 'subtask-input subtask-checked' : 'subtask-input'}`}
                  type='text'
                  value={sub.activity}
                  onChange={(e) => handleSubtaskChange(sub.id, e.target.value)}
                  onBlur={(e) => handleBlur(sub.id, e.target.value)}
                  placeholder='Enter sub task'
                  autoFocus
                />
              </div>
            </div>
          ))}
        </div>
      </div>

      <style>{`
        .task-card {
          padding: 10px;
          background-color: var(--secondary-color);
          border-radius: 5px;
          box-sizing: border-box;
          display: flex;
          flex-direction: column;
          width: 100%;
          max-width: 300px; /* Allow multiple cards in row */
        }

        .taskcard-header {
          display: flex;
          align-items: center;
          justify-content: space-between;
          padding: 5px;
          flex-direction: row;
        }

        .task-icons {
          display: flex;
          align-items: center;
        }

        .icon-button {
          background: none;
          border: none;
          cursor: pointer;
        }

        .icon-img {
          height: 20px;
          width: 30px;
        }

        .task-title {
          width: 100px;
          word-wrap: break-word;
          overflow-wrap: break-word;
          white-space: normal;
        }

        .sub-tasks {
          display: flex;
          flex-direction: column;
          margin-top: 10px;
        }

        .sub-task-items {
          width: 100%;
          display: flex;
          align-items: center;
          margin-bottom: 5px;
        }

        // .subtask-input {
        //   padding: 8px;
        //   border: none;
        //   background-color: var(--secondary-color);
        //   color: var(--text);
        //   font-family: 'Cedarville Cursive', cursive;
        //   margin-left: 8px;
        // }

        .subtask-input {
  padding: 8px;
  border: none;
  color: var(--text);
  font-family: 'Cedarville Cursive', cursive;
  background-color: var(--secondary-color);
  resize: none; /* optional: prevent manual resizing */
  width: 100%;
  overflow: hidden;
  line-height: 1.4;
  box-sizing: border-box;
}


        .subtask-checked {
          text-decoration: line-through;
          opacity: 0.6;
        }

        .subtask-checkbox {
          cursor: pointer;
        }
      `}</style>
    </>
  )
}

export default Taskcard
